const messageText = $input.first().json.message?.text?.toLowerCase() || '';
const chatId = String($input.first().json.message?.chat?.id || '');

if (!messageText) {
  return [{ json: { success: false, chatId, error: '❌ No text received.' } }];
}

// ──────────────────────────────────────────────
// Name detection & extraction
let lookupName = '';
const namePatterns = [
  /mohamed|mohammed/i,
  /ali|ail/i,
  /search\s+(?:for)?\s*([\w\s]+)/i,
  /find\s+([\w\s]+)/i,
  /email\s+(?:of|for)?\s*([\w\s]+)/i,
  /contact\s+([\w\s]+)/i
];

for (const regex of namePatterns) {
  const m = messageText.match(regex);
  if (m && m[1]) {
    lookupName = m[1].trim();
    break;
  } else if (m && m[0]) {
    lookupName = m[0].trim();
    break;
  }
}

// fallback: take first word longer than 3 chars if looks like name
if (!lookupName) {
  const words = messageText.split(/\s+/).filter(w => w.length > 3 && !['search','for','email','of','contact'].includes(w));
  if (words.length) lookupName = words[0];
}

lookupName = lookupName.replace(/[^\w\s]/g, '').trim();
const isLookup = !!lookupName && (messageText.includes('search') || messageText.includes('find') || messageText.includes('email') || messageText.includes('contact') || ['mohamed','ali','ail'].some(n => messageText.includes(n)));

// ──────────────────────────────────────────────
// Original parsing logic (emails + prompt)
let prompt = '';
let emailAddresses = [];

const promptMatch = $input.first().json.message.text.match(/\[PROMPT:\s*(.+?)\]/is);
const emailsMatch = $input.first().json.message.text.match(/\[EMAILS:\s*(.+?)\]/is);

if (promptMatch && emailsMatch) {
  prompt = promptMatch[1].trim();
  emailAddresses = emailsMatch[1].split(',').map(e => e.trim()).filter(e => e.includes('@'));
} else {
  const lines = $input.first().json.message.text.split('\n').map(l => l.trim()).filter(l => l.length > 0);
  prompt = lines[0] || '';
  for (let i = 1; i < lines.length; i++) {
    const emails = lines[i].split(',').map(e => e.trim()).filter(e => e.includes('@'));
    emailAddresses.push(...emails);
  }
}

if (!prompt) {
  return [{ json: { success: false, chatId, error: '❌ No prompt found.' } }];
}

return [{
  json: {
    success: true,
    prompt,
    emailAddresses,
    chatId,
    startTime: new Date().toISOString(),
    lookupName,
    isLookup
  }
}];

const parse = $input.first().json;
let emailAddresses = parse.emailAddresses || [];
let fromContacts = false;

if (parse.isLookup && items.length > 1) {
  // items[1] = contact match branch
  const contact = items[1].json;
  const email = contact.emailAddresses?.[0]?.value;
  if (email && !emailAddresses.includes(email)) {
    emailAddresses.push(email);
    fromContacts = true;
  }
}

const gmailQuery = emailAddresses.map(e => 'from:' + e).join(' OR ') || 'from:nobody-to-force-empty';

return [{
  json: {
    ...parse,
    emailAddresses,
    gmailQuery,
    fromContacts
  }
}];

const parseData = $('Parse Message1 + Name Detect').first().json;
const emailItems = $input.all();
let emailContent = '';

try {
  if (emailItems.length > 0 && emailItems[0].json.id) {
    emailContent = emailItems.map((item, i) => {
      const e = item.json;
      const body = e.snippet || e.textPlain || e.text || 'No content';
      return '--- Email ' + (i+1) + ' ---\nFrom: ' + (e.from || 'Unknown') + '\nSubject: ' + (e.subject || 'No Subject') + '\nDate: ' + (e.date || 'Unknown') + '\nContent: ' + body;
    }).join('\n\n');
  } else {
    emailContent = 'No emails found for the specified addresses.';
  }
} catch(e) {
  emailContent = 'Could not retrieve emails. Error: ' + e.message;
}

const fullPrompt = 'Analyze the following emails based on this request: "' + parseData.prompt + '"\n\nEmails:\n' + emailContent + '\n\nProvide a comprehensive analysis addressing the request. Be concise but thorough.';

const requestBody = JSON.stringify({
  model: 'llama-3.3-70b-versatile',
  messages: [
    { role: 'system', content: 'You are a professional email analyst. Provide clear, structured analysis.' },
    { role: 'user', content: fullPrompt }
  ],
  temperature: 0.7,
  max_tokens: 4096
});

return [{ json: { requestBody, chatId: parseData.chatId, prompt: parseData.prompt, emailAddresses: parseData.emailAddresses, startTime: parseData.startTime, emailCount: emailItems.length } }];

const data = $input.first().json;
const logEntry = {
  timestamp: new Date().toISOString(),
  prompt: $('Parse Message1 + Name Detect').first().json.prompt,
  emailsSearched: $('Parse Message1 + Name Detect').first().json.emailAddresses,
  responseLength: (data.llmResponse || '').length,
  executionTime: Date.now() - new Date(data.startTime).getTime()
};
console.log('Transaction Log:', JSON.stringify(logEntry));
return [{ json: { logEntry, ...data } }];

const groqRes = $input.first().json;
const parseData = $('Build LLM Request1').first().json;
let llmResponse = '';

try {
  if (groqRes.choices && groqRes.choices.length > 0) {
    llmResponse = groqRes.choices[0].message.content;
  } else if (groqRes.error) {
    llmResponse = '⚠️ API Error: ' + (groqRes.error.message || JSON.stringify(groqRes.error));
  } else {
    llmResponse = '⚠️ No response from AI model.';
  }
} catch(e) {
  llmResponse = '⚠️ Error processing response: ' + e.message;
}

let telegramResponse = '📊 Analysis Result:\n\n' + llmResponse;
if (telegramResponse.length > 4000) {
  telegramResponse = telegramResponse.substring(0, 3997) + '...';
}

const adminEmailHtml = '<h2>AI Email Analysis Report</h2><p><b>Request:</b> ' + parseData.prompt + '</p><p><b>Emails Searched:</b> ' + parseData.emailAddresses.join(', ') + (parseData.fromContacts ? ' (from contacts lookup)' : '') + '</p><p><b>Time:</b> ' + new Date().toISOString() + '</p><hr><h3>Analysis:</h3><p>' + llmResponse.replace(/\n/g, '<br>') + '</p>';

return [{ json: { telegramResponse, adminEmailHtml, adminEmailSubject: 'AI Analysis: ' + parseData.prompt.substring(0, 50), chatId: parseData.chatId, llmResponse, startTime: parseData.startTime } }];
